using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // BREAKING CHANGE 1 — Discriminator property renamed "$type" (was "Discriminator").
            // Existing 500K docs and direct SQL queries reference "Discriminator", so keep it.
            b.HasDiscriminator<string>("Discriminator")
             .HasValue<Product>("Product");

            // BREAKING CHANGE 2 — id values no longer include the discriminator prefix.
            // EF8 wrote id = "Product|123"; EF9 writes id = "123".
            // Preserve the old format so existing documents remain readable.
            b.Property(p => p.Id)
             .HasConversion(
                 id => $"Product|{id}",
                 cosmosId => int.Parse(cosmosId.Split('|')[1]));

            // BREAKING CHANGE 3 — HasIndex now throws on the Cosmos provider.
            // Cosmos manages its own indexes; the EF8 call was silently ignored.
            // REMOVED: b.HasIndex(p => p.Sku);
        });
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

